from typing import Optional, Tuple

import numpy as np

from genai_bench.scenarios.base import (
    EmbeddingDistribution,
    ReRankDistribution,
    Scenario,
    TextDistribution,
    parse_params_str,
)


class NormalDistribution(Scenario):
    """
    Normal distribution
    e.g.
    N(300,150)/(480,240)
    """

    scenario_type = TextDistribution.NORMAL
    validation_pattern = r"^N\(\d+,\d+\)\/\(\d+,\d+\)$"

    def __init__(
        self,
        mean_input_tokens: int,
        stddev_input_tokens: int,
        mean_output_tokens: int,
        stddev_output_tokens: int,
    ):
        self.mean_input_tokens = mean_input_tokens
        self.stddev_input_tokens = stddev_input_tokens
        self.mean_output_tokens = mean_output_tokens
        self.stddev_output_tokens = stddev_output_tokens

    def sample(self) -> Tuple[int, int]:
        num_input_tokens = max(
            1,
            int(np.random.normal(self.mean_input_tokens, self.stddev_input_tokens)),
        )
        num_output_tokens = max(
            2,
            int(np.random.normal(self.mean_output_tokens, self.stddev_output_tokens)),
        )
        return num_input_tokens, num_output_tokens

    def to_string(self) -> str:
        return (
            f"N({self.mean_input_tokens},{self.stddev_input_tokens})/"
            f"({self.mean_output_tokens},{self.stddev_output_tokens})"
        )

    @classmethod
    def parse(cls, params_str: str) -> "NormalDistribution":
        (mean_input, stddev_input), (mean_output, stddev_output) = parse_params_str(
            params_str
        )
        return cls(
            mean_input_tokens=mean_input,
            stddev_input_tokens=stddev_input,
            mean_output_tokens=mean_output,
            stddev_output_tokens=stddev_output,
        )


class UniformDistribution(Scenario):
    """
    Uniform distribution
    e.g.
    U(100,200)/(200,300),
    U(1000,100)
    """

    scenario_type = TextDistribution.UNIFORM
    validation_pattern = r"^U\(\d+,\d+\)(?:\/\(\d+,\d+\))?$"

    def __init__(
        self,
        max_input_tokens: int,
        max_output_tokens: int,
        min_input_tokens: Optional[int] = None,
        min_output_tokens: Optional[int] = None,
    ):
        self.min_input_tokens = min_input_tokens
        self.max_input_tokens = max_input_tokens
        self.min_output_tokens = min_output_tokens
        self.max_output_tokens = max_output_tokens

    def sample(self) -> Tuple[int, int]:
        num_input_tokens = max(
            1,
            int(np.random.uniform(self.min_input_tokens or 1, self.max_input_tokens)),
        )
        num_output_tokens = max(
            2,
            int(np.random.uniform(self.min_output_tokens or 1, self.max_output_tokens)),
        )
        return num_input_tokens, num_output_tokens

    def to_string(self) -> str:
        if self.min_input_tokens and self.min_output_tokens:
            return (
                f"U({self.min_input_tokens},{self.max_input_tokens})/"
                f"({self.min_output_tokens},{self.max_output_tokens})"
            )
        else:
            return f"U({self.max_input_tokens},{self.max_output_tokens})"

    @classmethod
    def parse(cls, params_str: str) -> "UniformDistribution":
        parsed_parts = parse_params_str(params_str)
        if len(parsed_parts) == 2:
            (min_input, max_input), (min_output, max_output) = parsed_parts
            return cls(
                min_input_tokens=min_input,
                max_input_tokens=max_input,
                min_output_tokens=min_output,
                max_output_tokens=max_output,
            )
        else:
            (
                max_input,
                max_output,
            ) = parsed_parts[0]
            return cls(
                max_input_tokens=max_input,
                max_output_tokens=max_output,
            )


class DeterministicDistribution(Scenario):
    """
    Deterministic Distribution, aka constant
    e.g.
    D(100,1000)
    """

    scenario_type = TextDistribution.DETERMINISTIC
    validation_pattern = r"^D\(\d+,\d+\)$"

    def __init__(self, num_input_tokens: int, num_output_tokens: int):
        self.num_input_tokens = num_input_tokens
        self.num_output_tokens = num_output_tokens

    def sample(self) -> Tuple[int, int]:
        return self.num_input_tokens, self.num_output_tokens

    def to_string(self) -> str:
        return f"D({self.num_input_tokens},{self.num_output_tokens})"

    @classmethod
    def parse(cls, params_str: str) -> "DeterministicDistribution":
        num_input, num_output = parse_params_str(params_str)[0]
        return cls(
            num_input_tokens=num_input,
            num_output_tokens=num_output,
        )


class EmbeddingScenario(Scenario):
    """
    A class to represent an embedding scenario
    e.g. E(tokens_per_document)
    """

    scenario_type = EmbeddingDistribution.EMBEDDING
    validation_pattern = r"^E\(\d+\)$"

    def __init__(self, tokens_per_document: int):
        self.tokens_per_document = tokens_per_document

    def sample(self) -> int:
        """Returns tokens per document"""
        return self.tokens_per_document

    def to_string(self) -> str:
        """
        Returns the embedding scenario object back in its string representation.
        For example E(1024).
        """
        return f"E({self.tokens_per_document})"

    @classmethod
    def parse(cls, params_str: str) -> "EmbeddingScenario":
        """
        Parse the embedding scenario from a string, e.g. E(1024)
        """
        tokens_per_document = int(params_str[1:-1])
        return cls(tokens_per_document=tokens_per_document)


class ReRankScenario(Scenario):
    """
    A class to represent re-rank scenario
    e.g. R(tokens_per_document,tokens_per_query)
    """

    scenario_type = ReRankDistribution.RE_RANK
    validation_pattern = r"^R\(\d+,\d+\)$"

    def __init__(self, tokens_per_document: int, tokens_per_query: int):
        self.tokens_per_document = tokens_per_document
        self.tokens_per_query = tokens_per_query

    def sample(self) -> Tuple[int, int]:
        """Returns tokens per document"""
        return self.tokens_per_document, self.tokens_per_query

    def to_string(self) -> str:
        """
        Returns the re-rank scenario object back in its string representation.
        For example R(1024,100).
        """
        return f"R({self.tokens_per_document},{self.tokens_per_query})"

    @classmethod
    def parse(cls, params_str: str) -> "ReRankScenario":
        """
        Parse the re-rank scenario from a string, e.g. R(1024,100)
        """
        tokens_per_document, tokens_per_query = parse_params_str(params_str)[0]
        return cls(
            tokens_per_document=tokens_per_document, tokens_per_query=tokens_per_query
        )

from locust import HttpUser

from typing import Dict

from genai_bench.logging import init_logger
from genai_bench.metrics.request_metrics_collector import RequestMetricsCollector
from genai_bench.protocol import UserRequest, UserResponse

logger = init_logger(__name__)


class BaseUser(HttpUser):
    supported_tasks: Dict[str, str] = {}

    def __new__(cls, *args, **kwargs):
        if cls is BaseUser:
            raise TypeError("BaseUser is not meant to be instantiated directly.")
        return super().__new__(cls)

    def __init__(self, *args, **kwargs) -> None:
        super().__init__(*args, **kwargs)

    @classmethod
    def is_task_supported(cls, task: str) -> bool:
        return task in cls.supported_tasks

    def sample(self) -> UserRequest:
        if not (
            hasattr(self.environment, "scenario")
            and self.environment.scenario is not None
        ):
            raise AttributeError(
                f"Environment {self.environment} has no attribute "
                f"'scenario' or it is empty."
            )
        if not (
            hasattr(self.environment, "sampler")
            and self.environment.sampler is not None
        ):
            raise AttributeError(
                f"Environment {self.environment} has no attribute "
                f"'sampler' or it is empty."
            )
        return self.environment.sampler.sample(self.environment.scenario)

    def collect_metrics(
        self,
        user_response: UserResponse,
        endpoint: str,
    ):
        """
        Collects metrics based on the UserResponse.

        Args:
            user_response (UserResponse): The response object containing the
                request metrics.
            endpoint (str): The API endpoint for the request.
        """
        request_metrics_collector = RequestMetricsCollector()
        if user_response.status_code == 200:
            request_metrics_collector.calculate_metrics(user_response)
            self.environment.events.request.fire(
                request_type="POST",
                name=endpoint,
                response_time=request_metrics_collector.metrics.e2e_latency,
                response_length=request_metrics_collector.metrics.num_output_tokens,
            )
        else:
            # Handle error responses
            request_metrics_collector.metrics.error_code = user_response.status_code
            request_metrics_collector.metrics.error_message = (
                user_response.error_message
            )
            self.environment.events.request.fire(
                request_type="POST",
                name=endpoint,
                response_time=0,
                response_length=0,
                exception=f"Request failed with "
                f"status {user_response.status_code}, "
                f"message: {user_response.error_message}",
            )
            logger.warning(
                f"Received error response from server. Error code:"
                f" {user_response.status_code},"
                f" message: {user_response.error_message}."
            )

        # Send metrics to aggregated_metrics_collector
        self.environment.runner.send_message(
            "request_metrics", request_metrics_collector.metrics.model_dump_json()
        )  # type: ignore[attr-defined]

from typing import Optional, Tuple

from genai_bench.scenarios.base import MultiModality, Scenario, parse_params_str


class AudioModality(Scenario):
    """
    Audio output scenario for text-to-speech.
    A(num_input_chars)
    Example: A(500) — synthesize exactly 500 characters of text
    """

    scenario_type = MultiModality.AUDIO
    validation_pattern = r"^A\(\d+\)$"

    def __init__(self, num_input_chars: int):
        self.num_input_chars = num_input_chars

    def sample(self) -> int:
        return self.num_input_chars

    def to_string(self) -> str:
        return f"A({self.num_input_chars})"

    @classmethod
    def parse(cls, params_str: str) -> "AudioModality":
        (num_input_chars,) = parse_params_str(params_str)[0]
        return cls(num_input_chars=num_input_chars)


class ImageModality(Scenario):
    """
    Image input and text output
    e.g.
    I(256,256) or
    I(2048,2048,2)
    The third number represents the
    number of images
    """

    scenario_type = MultiModality.IMAGE
    validation_pattern = r"^I\(\d+,\d+(?:,\d+)?\)$"

    def __init__(
        self,
        num_input_dimension_width: int,
        num_input_dimension_height: int,
        num_input_images: int = 1,
        max_output_token: Optional[int] = None,
    ):
        self.num_input_dimension_width = num_input_dimension_width
        self.num_input_dimension_height = num_input_dimension_height
        self.num_input_images = num_input_images
        self.max_output_token = max_output_token

    def sample(self) -> Tuple[Tuple[int, int], int, int | None]:
        return (
            (
                self.num_input_dimension_width,
                self.num_input_dimension_height,
            ),
            self.num_input_images,
            self.max_output_token,
        )

    def to_string(self) -> str:  # TODO: include max_output_token in the string
        if self.num_input_images == 1:
            return (
                f"I({self.num_input_dimension_width},{self.num_input_dimension_height})"
            )
        else:
            return (
                f"I({self.num_input_dimension_width},"
                f"{self.num_input_dimension_height},"
                f"{self.num_input_images})"
            )

    @classmethod
    def parse(cls, params_str: str) -> "ImageModality":
        num_input_dimension_width, num_input_dimension_height, *optional = (
            parse_params_str(params_str)[0]
        )
        if not optional:
            return cls(
                num_input_dimension_width=num_input_dimension_width,
                num_input_dimension_height=num_input_dimension_height,
            )
        else:
            return cls(
                num_input_dimension_width=num_input_dimension_width,
                num_input_dimension_height=num_input_dimension_height,
                num_input_images=optional[0],
            )
